1	/**
2	 * Structural operations under the two-regime algebra
3	 * (docs/research/04-open-questions.md):
4	 *
5	 *   HEADINGS         indent/outdent = level ± 1, whole subtree shifts,
6	 *                    hierarchy re-derives from levels; reject at h1/h6.
7	 *   EVERYTHING ELSE  indent = child of previous sibling, outdent =
8	 *                    brother→uncle; encoding recomputed from context.
9	 *
10	 * Implementation strategy: each op performs line surgery on the tree, then
11	 * the canonical result is parse(encode(surgery)) — closure with the mapping
12	 * holds by construction, and the inverse-law tests guard semantics.
13	 *
14	 * Markdown-imposed rejections beyond the bounds:
15	 * - content cannot become a *sibling of a heading section it is inside*
16	 *   (heading scope is positional), so outdent out of a heading is rejected;
17	 * - only list items can nest under a paragraph, and nothing nests under an
18	 *   atom;
19	 * - reordering across the heading/content divide (or between heading
20	 *   levels) has no positional encoding and is rejected.
21	 */
22	
23	import type { OutlineDoc, OutlineNode } from './model';
24	import { findPath, isAtom, makeNode, nodeAt, updateSiblings } from './model';
25	import { encode, encodeLines } from './encode';
26	import { parse, indentWidth } from './parse';
27	import type { Edit, OpResult } from './result';
28	import { accept, diffLines, reject } from './result';
29	import { encodingKindAtDestination } from './rules';
30	import {
31	  headingWithLevel,
32	  leadingWhitespace,
33	  markerWidth,
34	  reencodeForDestination,
35	} from './reencode';
36	
37	export interface OpOutput {
38	  readonly doc: OutlineDoc;
39	  readonly edits: readonly Edit[];
40	  /**
41	   * Where the operated-on node landed: its first line (0-based, in the new
42	   * text) and the character offset of its content start (after indentation
43	   * and any list/heading marker) — ready to become an editor cursor.
44	   */
45	  readonly cursor: { readonly line: number; readonly ch: number };
46	}
47	
48	const isContent = (node: OutlineNode): boolean =>
49	  node.kind === 'paragraph' || node.kind === 'list-item';
50	
51	function childrenAt(doc: OutlineDoc, path: readonly number[]): readonly OutlineNode[] {
52	  return path.length === 0 ? doc.children : (nodeAt(doc, path)?.children ?? []);
53	}
54	
55	/** Char offset where a line's content starts (after indent + marker). */
56	function contentColumnCh(line: string): number {
57	  const match = /^[ \t]*(?:(?:[-+*]|\d{1,9}[.)])[ \t]+)?(?:#{1,6}[ \t]+)?/.exec(line);
58	  return match ? match[0].length : 0;
59	}
60	
61	/** Start line of a node in a doc's encoding (ids preserved from surgery). */
62	function startLineOf(doc: OutlineDoc, id: number): number {
63	  let line = doc.preamble.length;
64	  let found = -1;
65	  const walk = (node: OutlineNode): void => {
66	    if (found !== -1) return;
67	    if (node.id === id) {
68	      found = line;
69	      return;
70	    }
71	    line += node.lines.length + node.trailingGap.length;
72	    node.children.forEach(walk);
73	  };
74	  doc.children.forEach(walk);
75	  return found === -1 ? 0 : found;
76	}
77	
78	function finalize(
79	  oldDoc: OutlineDoc,
80	  surgery: OutlineDoc,
81	  subjectId: number,
82	): OpResult<OpOutput> {
83	  const normalized = normalizeBoundaries(surgery);
84	  const text = encode(normalized);
85	  const lines = text === '' ? [] : text.split('\n');
86	  const subjectLine = startLineOf(normalized, subjectId);
87	  return accept({
88	    doc: parse(text),
89	    edits: diffLines(encodeLines(oldDoc), lines),
90	    cursor: { line: subjectLine, ch: contentColumnCh(lines[subjectLine] ?? '') },
91	  });
92	}
93	
94	// ---------------------------------------------------------------- headings
95	
96	function shiftHeadingLevels(node: OutlineNode, delta: number): OutlineNode {
97	  const self =
98	    node.kind === 'heading' ? headingWithLevel(node, (node.level ?? 1) + delta) : node;
99	  return { ...self, children: self.children.map((child) => shiftHeadingLevels(child, delta)) };
100	}
101	
102	function maxHeadingLevel(node: OutlineNode): number {
103	  let max = node.kind === 'heading' ? (node.level ?? 1) : 0;
104	  for (const child of node.children) max = Math.max(max, maxHeadingLevel(child));
105	  return max;
106	}
107	
108	function headingLevelOp(
109	  doc: OutlineDoc,
110	  path: readonly number[],
111	  node: OutlineNode,
112	  delta: number,
113	): OpResult<OpOutput> {
114	  if (delta > 0 && maxHeadingLevel(node) >= 6) return reject('at-h6-bound');
115	  if (delta < 0 && (node.level ?? 1) <= 1) return reject('at-h1-bound');
116	  const surgery = updateSiblings(doc, path.slice(0, -1), (siblings) =>
117	    siblings.map((sibling, i) =>
118	      i === path[path.length - 1] ? shiftHeadingLevels(sibling, delta) : sibling,
119	    ),
120	  );
121	  return finalize(doc, surgery, node.id);
122	}
123	
124	// ------------------------------------------------------- separation repair
125	
126	function subtreeFinalNode(node: OutlineNode): OutlineNode {
127	  const last = node.children[node.children.length - 1];
128	  return last ? subtreeFinalNode(last) : node;
129	}
130	
131	function appendFinalGap(node: OutlineNode): OutlineNode {
132	  const last = node.children[node.children.length - 1];
133	  if (!last) return { ...node, trailingGap: [...node.trailingGap, ''] };
134	  return {
135	    ...node,
136	    children: [...node.children.slice(0, -1), appendFinalGap(last)],
137	  };
138	}
139	
140	function stripFinalGap(node: OutlineNode): OutlineNode {
141	  const last = node.children[node.children.length - 1];
142	  if (!last) return { ...node, trailingGap: [] };
143	  return { ...node, children: [...node.children.slice(0, -1), stripFinalGap(last)] };
144	}
145	
146	function setFinalGap(node: OutlineNode, gap: readonly string[]): OutlineNode {
147	  const last = node.children[node.children.length - 1];
148	  if (!last) return { ...node, trailingGap: [...gap] };
149	  return { ...node, children: [...node.children.slice(0, -1), setFinalGap(last, gap)] };
150	}
151	
152	function needsBlankBetween(prev: OutlineNode, next: OutlineNode): boolean {
153	  const leaf = subtreeFinalNode(prev);
154	  if (leaf.trailingGap.length > 0) return false;
155	  if (leaf.kind === 'paragraph') {
156	    return (
157	      next.kind === 'paragraph' ||
158	      next.kind === 'html' ||
159	      (next.kind === 'heading' && next.setext === true) ||
160	      (next.kind === 'hr' && (next.lines[0] ?? '').includes('-'))
161	    );
162	  }
163	  if (leaf.kind === 'list-item') {
164	    const contentCol = indentWidth(leaf.lines[0] ?? '') + markerWidth(leaf);
165	    return (
166	      (next.kind === 'paragraph' || next.kind === 'html') &&
167	      indentWidth(next.lines[0] ?? '') >= contentCol
168	    );
169	  }
170	  return false;
171	}
172	
173	/**
174	 * Insert the blank lines that keep adjacent blocks from merging on reparse.
175	 * On any tree that came out of `parse` this is a no-op — such boundaries
176	 * cannot exist there — so it only ever touches op-created seams.
177	 */
178	function normalizeBoundaries(doc: OutlineDoc): OutlineDoc {
179	  const fixList = (nodes: readonly OutlineNode[]): readonly OutlineNode[] => {
180	    const out = nodes.map((node) => {
181	      let fixed: OutlineNode = { ...node, children: fixList(node.children) };
182	      const firstChild = fixed.children[0];
183	      if (
184	        firstChild &&
185	        fixed.kind === 'list-item' &&
186	        fixed.trailingGap.length === 0 &&
187	        (firstChild.kind === 'paragraph' || firstChild.kind === 'html')
188	      ) {
189	        fixed = { ...fixed, trailingGap: [''] };
190	      }
191	      return fixed;
192	    });
193	    return out.map((node, i) =>
194	      i < out.length - 1 && needsBlankBetween(node, out[i + 1]!) ? appendFinalGap(node) : node,
195	    );
196	  };
197	  return { ...doc, children: fixList(doc.children) };
198	}
199	
200	// ------------------------------------------------------ ordered renumbering
201	
202	const ORDERED_MARKER_RE = /^([ \t]*)\d{1,9}([.)])/;
203	
204	/**
205	 * Renumber maximal runs of ordered items. A run keeps its start number
206	 * (taken as the minimum present, so a swap doesn't inherit the moved item's
207	 * number while `5. 6. 7.`-style lists keep starting at 5).
208	 */
209	function renumberOrdered(nodes: readonly OutlineNode[]): readonly OutlineNode[] {
210	  const isOrdered = (n: OutlineNode): boolean =>
211	    n.kind === 'list-item' && n.listStyle?.type === 'ordered';
212	
213	  const out = [...nodes];
214	  let i = 0;
215	  while (i < out.length) {
216	    if (!isOrdered(out[i]!)) {
217	      i++;
218	      continue;
219	    }
220	    let end = i;
221	    while (end < out.length && isOrdered(out[end]!)) end++;
222	    const run = out.slice(i, end);
223	    const startNumber = Math.min(
224	      ...run.map((n) => (n.listStyle as { number: number }).number),
225	    );
226	    run.forEach((node, k) => {
227	      const number = startNumber + k;
228	      const style = node.listStyle as { type: 'ordered'; number: number; delimiter: '.' | ')' };
229	      if (style.number === number) return;
230	      out[i + k] = {
231	        ...node,
232	        listStyle: { ...style, number },
233	        lines: node.lines.map((line, li) =>
234	          li === 0 ? line.replace(ORDERED_MARKER_RE, `$1${number}$2`) : line,
235	        ),
236	      };
237	    });
238	    i = end;
239	  }
240	  return out;
241	}
242	
243	/**
244	 * The indentation STRING a node adopts at its destination — taken verbatim
245	 * from context (so tab-indented vaults stay tab-indented):
246	 * 1. an existing list-item at the landing site (sibling-to-be),
247	 * 2. else the parent's own indentation plus one inferred unit (list-item
248	 *    parents) or exactly the parent's indentation (paragraph parents),
249	 * 3. else '' under headings/root.
250	 */
251	function destinationIndent(
252	  doc: OutlineDoc,
253	  parent: OutlineNode | 'root',
254	  siblingsAtDestination: readonly OutlineNode[],
255	): string {
256	  const sibling = siblingsAtDestination.find((n) => n.kind === 'list-item');
257	  if (sibling) return leadingWhitespace(sibling.lines[0] ?? '');
258	  if (parent === 'root' || parent.kind === 'heading') return '';
259	  const parentIndent = leadingWhitespace(parent.lines[0] ?? '');
260	  if (parent.kind === 'paragraph') return parentIndent;
261	  return parentIndent + inferIndentUnit(doc);
262	}
263	
264	/** The document's list indent unit: tab if any indented list line uses one,
265	 * else the first indented item's spaces, else two spaces. */
266	function inferIndentUnit(doc: OutlineDoc): string {
267	  for (const node of walkDoc(doc)) {
268	    if (node.kind !== 'list-item') continue;
269	    const ws = leadingWhitespace(node.lines[0] ?? '');
270	    if (ws.includes('\t')) return '\t';
271	    if (ws.length > 0) return ws.length >= 4 ? '    ' : ws;
272	  }
273	  return '  ';
274	}
275	
276	function* walkDoc(doc: OutlineDoc): Generator<OutlineNode> {
277	  function* walk(nodes: readonly OutlineNode[]): Generator<OutlineNode> {
278	    for (const node of nodes) {
279	      yield node;
280	      yield* walk(node.children);
281	    }
282	  }
283	  yield* walk(doc.children);
284	}
285	
286	// ------------------------------------------------------------------ indent
287	
288	export function indent(doc: OutlineDoc, nodeId: number): OpResult<OpOutput> {
289	  const path = findPath(doc, nodeId);
290	  if (!path) return reject('node-not-found');
291	  const node = nodeAt(doc, path)!;
292	
293	  if (node.kind === 'heading') return headingLevelOp(doc, path, node, +1);
294	
295	  const parentPath = path.slice(0, -1);
296	  const index = path[path.length - 1]!;
297	  const siblings = childrenAt(doc, parentPath);
298	  if (index === 0) return reject('no-previous-sibling');
299	  const target = siblings[index - 1]!;
300	
301	  if (isAtom(target)) return reject('not-expressible-under-target');
302	  if (target.kind === 'paragraph' && !isContent(node)) {
303	    // Only list items can follow a paragraph as its children.
304	    return reject('not-expressible-under-target');
305	  }
306	
307	  // Under a heading, direct content ends at the first sub-heading — insert
308	  // there so the node lands in the target's own section, not a child's.
309	  const firstSubheading = target.children.findIndex((child) => child.kind === 'heading');
310	  const insertIndex =
311	    target.kind === 'heading' && firstSubheading !== -1
312	      ? firstSubheading
313	      : target.children.length;
314	
315	  const newKind = isContent(node)
316	    ? encodingKindAtDestination({
317	        parentKind: target.kind,
318	        precedingSiblings: target.children.slice(0, insertIndex),
319	        followingSiblings: target.children.slice(insertIndex),
320	      })
321	    : undefined;
322	  const moved = reencodeForDestination(
323	    node,
324	    newKind,
325	    destinationIndent(doc, target, target.children.slice(0, insertIndex)),
326	  );
327	
328	  let surgery = updateSiblings(doc, parentPath, (nodes) => {
329	    const rest = nodes.filter((_, i) => i !== index);
330	    return renumberOrdered(rest);
331	  });
332	  surgery = updateSiblings(surgery, [...parentPath, index - 1], (nodes) =>
333	    renumberOrdered([...nodes.slice(0, insertIndex), moved, ...nodes.slice(insertIndex)]),
334	  );
335	  return finalize(doc, surgery, moved.id);
336	}
337	
338	// ----------------------------------------------------------------- outdent
339	
340	export function outdent(doc: OutlineDoc, nodeId: number): OpResult<OpOutput> {
341	  const path = findPath(doc, nodeId);
342	  if (!path) return reject('node-not-found');
343	  const node = nodeAt(doc, path)!;
344	
345	  if (node.kind === 'heading') return headingLevelOp(doc, path, node, -1);
346	
347	  if (path.length === 1) return reject('at-top-level');
348	  const parentPath = path.slice(0, -1);
349	  const index = path[path.length - 1]!;
350	  const parent = nodeAt(doc, parentPath)!;
351	
352	  if (parent.kind === 'heading') {
353	    // Heading scope is positional: content placed after a section's body is
354	    // still inside the section — there is no "sibling of my heading" spot.
355	    return reject('not-expressible-under-target');
356	  }
357	
358	  const grandPath = parentPath.slice(0, -1);
359	  const parentIndex = parentPath[parentPath.length - 1]!;
360	  const grandParent = grandPath.length === 0 ? undefined : nodeAt(doc, grandPath)!;
361	  if (grandPath.length > 0 && grandParent!.kind === 'heading' && node.kind !== 'paragraph' && node.kind !== 'list-item' && !isAtom(node)) {
362	    return reject('not-expressible-under-target');
363	  }
364	  const grandSiblings = childrenAt(doc, grandPath);
365	
366	  const newKind = isContent(node)
367	    ? encodingKindAtDestination({
368	        parentKind: grandParent ? grandParent.kind : 'root',
369	        precedingSiblings: grandSiblings.slice(0, parentIndex + 1),
370	        followingSiblings: grandSiblings.slice(parentIndex + 1),
371	      })
372	    : undefined;
373	  const moved = reencodeForDestination(
374	    node,
375	    newKind,
376	    // Brother→uncle: the node lands at its former parent's level, so it
377	    // adopts the parent's own indentation string.
378	    node.kind === 'list-item' || newKind === 'list-item'
379	      ? leadingWhitespace(parent.lines[0] ?? '')
380	      : destinationIndent(doc, grandParent ?? 'root', []),
381	  );
382	
383	  let surgery = updateSiblings(doc, parentPath, (nodes) =>
384	    renumberOrdered(nodes.filter((_, i) => i !== index)),
385	  );
386	  surgery = updateSiblings(surgery, grandPath, (nodes) =>
387	    renumberOrdered([
388	      ...nodes.slice(0, parentIndex + 1),
389	      moved,
390	      ...nodes.slice(parentIndex + 1),
391	    ]),
392	  );
393	  return finalize(doc, surgery, moved.id);
394	}
395	
396	// -------------------------------------------------------------- reordering
397	
398	function move(doc: OutlineDoc, nodeId: number, delta: -1 | 1): OpResult<OpOutput> {
399	  const path = findPath(doc, nodeId);
400	  if (!path) return reject('node-not-found');
401	  const node = nodeAt(doc, path)!;
402	  const parentPath = path.slice(0, -1);
403	  const index = path[path.length - 1]!;
404	  const siblings = childrenAt(doc, parentPath);
405	  const other = siblings[index + delta];
406	  if (!other) return reject(delta < 0 ? 'no-sibling-above' : 'no-sibling-below');
407	
408	  const bothHeadings = node.kind === 'heading' && other.kind === 'heading';
409	  if (node.kind === 'heading' || other.kind === 'heading') {
410	    // Positional encoding only supports swapping same-level sections.
411	    if (!bothHeadings || node.level !== other.level) {
412	      return reject('cannot-reorder-across-heading-boundary');
413	    }
414	  }
415	
416	  const surgery = updateSiblings(doc, parentPath, (nodes) => {
417	    const out = [...nodes];
418	    const a = Math.min(index, index + delta);
419	    // Separator gaps are positional, not node-owned: the gap that followed
420	    // slot a stays at slot a (else the final-newline gap migrates mid-doc).
421	    const gapA = subtreeFinalNode(out[a]!).trailingGap;
422	    const gapB = subtreeFinalNode(out[a + 1]!).trailingGap;
423	    [out[a], out[a + 1]] = [setFinalGap(out[a + 1]!, gapA), setFinalGap(out[a]!, gapB)];
424	    return renumberOrdered(out);
425	  });
426	  return finalize(doc, surgery, node.id);
427	}
428	
429	export const moveUp = (doc: OutlineDoc, nodeId: number): OpResult<OpOutput> =>
430	  move(doc, nodeId, -1);
431	export const moveDown = (doc: OutlineDoc, nodeId: number): OpResult<OpOutput> =>
432	  move(doc, nodeId, 1);
433	
434	// ------------------------------------------------------------------- split
435	
436	const LIST_MARKER_SPLIT_RE = /^([ \t]*)([-+*]|\d{1,9}[.)])([ \t]*)/;
437	
438	/**
439	 * Split a paragraph/list-item node at a document position into two adjacent
440	 * same-kind siblings; children stay with the original (upper) node.
441	 *
442	 * Markdown nuance: an empty PARAGRAPH has no encoding (a blank line is a
443	 * gap), so an end-of-paragraph split yields no new node — just the blank
444	 * separation with the cursor on it; the sibling materializes when text is
445	 * typed. An empty list item ("-") is a real node.
446	 */
447	export function splitNode(
448	  doc: OutlineDoc,
449	  nodeId: number,
450	  position: { line: number; ch: number },
451	): OpResult<OpOutput> {
452	  const path = findPath(doc, nodeId);
453	  if (!path) return reject('node-not-found');
454	  const node = nodeAt(doc, path)!;
455	  if (node.kind !== 'paragraph' && node.kind !== 'list-item') return reject('cannot-split');
456	
457	  const startLine = startLineOf(doc, nodeId);
458	  const lineIndex = position.line - startLine;
459	  if (lineIndex < 0 || lineIndex >= node.lines.length) return reject('cannot-split');
460	  const line = node.lines[lineIndex]!;
461	  // Never split inside indentation or a list marker.
462	  const ch = Math.min(Math.max(position.ch, contentColumnCh(line)), line.length);
463	
464	  const upperLines = [...node.lines.slice(0, lineIndex), line.slice(0, ch)];
465	  const remainderFirst = line.slice(ch);
466	  const lowerRest = node.lines.slice(lineIndex + 1);
467	  const emptyRemainder = remainderFirst.trim() === '' && lowerRest.length === 0;
468	
469	  const parentPath = path.slice(0, -1);
470	  const index = path[path.length - 1]!;
471	
472	  if (node.kind === 'paragraph' && emptyRemainder) {
473	    // End-of-paragraph split: no empty-paragraph encoding exists, so widen
474	    // the gap and put the cursor on a line that is blank-separated on BOTH
475	    // sides — typing there materializes the sibling instead of rejoining a
476	    // neighbor.
477	    const surgery = updateSiblings(doc, parentPath, (nodes) =>
478	      nodes.map((n, i) => (i === index ? { ...n, trailingGap: ['', '', ...n.trailingGap] } : n)),
479	    );
480	    const result = finalize(doc, surgery, nodeId);
481	    if (!result.ok) return result;
482	    return accept({
483	      ...result.value,
484	      cursor: { line: startLine + node.lines.length + 1, ch: 0 },
485	    });
486	  }
487	
488	  let lower: OutlineNode;
489	  if (node.kind === 'list-item') {
490	    const match = LIST_MARKER_SPLIT_RE.exec(node.lines[0] ?? '')!;
491	    const markerPrefix = `${match[1]}${match[2]} `;
492	    const firstLine = emptyRemainder
493	      ? markerPrefix
494	      : `${markerPrefix}${remainderFirst.trimStart()}`;
495	    lower = makeNode({
496	      kind: 'list-item',
497	      ...(node.listStyle ? { listStyle: node.listStyle } : {}),
498	      lines: [firstLine, ...lowerRest],
499	    });
500	  } else {
501	    lower = makeNode({
502	      kind: 'paragraph',
503	      lines: [remainderFirst, ...lowerRest],
504	    });
505	  }
506	
507	  // The gap that separated the node's SUBTREE from what follows moves to the
508	  // lower half — it is now what precedes the next sibling.
509	  let upper: OutlineNode = { ...node, lines: upperLines };
510	  const finalGap = subtreeFinalNode(upper).trailingGap;
511	  upper = stripFinalGap(upper);
512	  lower = { ...lower, trailingGap: [...finalGap] };
513	
514	  const surgery = updateSiblings(doc, parentPath, (nodes) =>
515	    renumberOrdered([...nodes.slice(0, index), upper, lower, ...nodes.slice(index + 1)]),
516	  );
517	  return finalize(doc, surgery, lower.id);
518	}
