1	/** Ops never throw for algebra reasons: rejections are values (design.md D3). */
2	
3	export type RejectionReason =
4	  | 'node-not-found'
5	  | 'at-h1-bound'
6	  | 'at-h6-bound'
7	  | 'no-previous-sibling'
8	  | 'at-top-level'
9	  | 'no-sibling-above'
10	  | 'no-sibling-below'
11	  | 'not-expressible-under-target'
12	  | 'cannot-reorder-across-heading-boundary'
13	  | 'cannot-split';
14	
15	export interface Rejection {
16	  readonly reason: RejectionReason;
17	}
18	
19	/** Replace lines [fromLine, toLine) of the source with `insert`. */
20	export interface Edit {
21	  readonly fromLine: number;
22	  readonly toLine: number;
23	  readonly insert: readonly string[];
24	}
25	
26	export type OpResult<T> =
27	  | { readonly ok: true; readonly value: T }
28	  | { readonly ok: false; readonly rejection: Rejection };
29	
30	export const accept = <T>(value: T): OpResult<T> => ({ ok: true, value });
31	export const reject = <T>(reason: RejectionReason): OpResult<T> => ({
32	  ok: false,
33	  rejection: { reason },
34	});
35	
36	/** Single-splice diff: the minimal contiguous line replacement. */
37	export function diffLines(before: readonly string[], after: readonly string[]): Edit[] {
38	  let prefix = 0;
39	  while (prefix < before.length && prefix < after.length && before[prefix] === after[prefix]) {
40	    prefix++;
41	  }
42	  let suffix = 0;
43	  while (
44	    suffix < before.length - prefix &&
45	    suffix < after.length - prefix &&
46	    before[before.length - 1 - suffix] === after[after.length - 1 - suffix]
47	  ) {
48	    suffix++;
49	  }
50	  if (prefix === before.length && prefix === after.length) return [];
51	  return [
52	    {
53	      fromLine: prefix,
54	      toLine: before.length - suffix,
55	      insert: after.slice(prefix, after.length - suffix),
56	    },
57	  ];
58	}
59	
60	export function applyEdits(source: readonly string[], edits: readonly Edit[]): string[] {
61	  const out = [...source];
62	  // Edits are non-overlapping and ordered; apply from the end.
63	  for (const edit of [...edits].sort((a, b) => b.fromLine - a.fromLine)) {
64	    out.splice(edit.fromLine, edit.toLine - edit.fromLine, ...edit.insert);
65	  }
66	  return out;
67	}
