1	/**
2	 * Selection escalation math (design.md D4): a non-empty selection range
3	 * that crosses a node boundary expands to the minimal contiguous cover of
4	 * whole sibling subtrees. Pure module — no CodeMirror imports; the CM6
5	 * adapter (src/plugin/transaction-filter.ts) converts to/from character
6	 * offsets and handles multi-range selections (each range escalates
7	 * independently, per D4 — that iteration lives in the adapter, not here).
8	 */
9	
10	import type { NodePath, OutlineDoc, OutlineNode } from './model';
11	import { findPath } from './model';
12	import { nodeAtLine } from './locate';
13	
14	export interface LinePos {
15	  readonly line: number;
16	  readonly ch: number;
17	}
18	
19	/** A selection range with orientation preserved: `anchor` is the drag/
20	 * extend origin, `head` is the current end — `head` may be before or after
21	 * `anchor` in document order ("backward" vs "forward"). */
22	export interface LineRange {
23	  readonly anchor: LinePos;
24	  readonly head: LinePos;
25	}
26	
27	function isEmpty(range: LineRange): boolean {
28	  return range.anchor.line === range.head.line && range.anchor.ch === range.head.ch;
29	}
30	
31	function posBefore(a: LinePos, b: LinePos): boolean {
32	  return a.line < b.line || (a.line === b.line && a.ch < b.ch);
33	}
34	
35	function isBackward(range: LineRange): boolean {
36	  return posBefore(range.head, range.anchor);
37	}
38	
39	function posEqual(a: LinePos, b: LinePos): boolean {
40	  return a.line === b.line && a.ch === b.ch;
41	}
42	
43	export function rangesEqual(a: LineRange, b: LineRange): boolean {
44	  return posEqual(a.anchor, b.anchor) && posEqual(a.head, b.head);
45	}
46	
47	/** A node's own absolute start line (0-based) in `doc`. */
48	function startLineOf(doc: OutlineDoc, target: OutlineNode): number {
49	  let line = doc.preamble.length;
50	  let found = -1;
51	  const walk = (node: OutlineNode): void => {
52	    if (found !== -1) return;
53	    if (node === target) {
54	      found = line;
55	      return;
56	    }
57	    line += node.lines.length + node.trailingGap.length;
58	    node.children.forEach(walk);
59	  };
60	  doc.children.forEach(walk);
61	  return found;
62	}
63	
64	/** Total line count of a node's own subtree (its lines + gap, plus every
65	 * descendant's), for skipping past a preceding sibling wholesale. */
66	function subtreeLineCount(node: OutlineNode): number {
67	  let count = node.lines.length + node.trailingGap.length;
68	  for (const child of node.children) count += subtreeLineCount(child);
69	  return count;
70	}
71	
72	/**
73	 * The end position of a subtree's OWN content: the last line of its
74	 * deepest last-descendant's `lines`, excluding that leaf's trailing gap
75	 * (D4: "trailing gap lines excluded from the visual selection but owned
76	 * for Phase C semantics"). `startLine` is `node`'s own absolute start line.
77	 */
78	function subtreeContentEnd(node: OutlineNode, startLine: number): LinePos {
79	  if (node.children.length === 0) {
80	    const lastLine = node.lines[node.lines.length - 1] ?? '';
81	    return { line: startLine + node.lines.length - 1, ch: lastLine.length };
82	  }
83	  let line = startLine + node.lines.length + node.trailingGap.length;
84	  // Preceding siblings must be skipped by their FULL subtree size — a
85	  // sibling's own lines+gap alone undercounts it if it has descendants of
86	  // its own (the bug a naive `sibling.lines.length + sibling.trailingGap.
87	  // length` sum would introduce: it silently landed inside an earlier
88	  // sibling's subtree instead of at the actual last child).
89	  for (let i = 0; i < node.children.length - 1; i++) {
90	    line += subtreeLineCount(node.children[i]!);
91	  }
92	  return subtreeContentEnd(node.children[node.children.length - 1]!, line);
93	}
94	
95	function childrenAtScope(doc: OutlineDoc, scopePath: NodePath): readonly OutlineNode[] {
96	  let list: readonly OutlineNode[] = doc.children;
97	  for (const index of scopePath) list = list[index]!.children;
98	  return list;
99	}
100	
101	interface Cover {
102	  readonly start: LinePos;
103	  readonly end: LinePos;
104	}
105	
106	function subtreeCoverOf(doc: OutlineDoc, node: OutlineNode): Cover {
107	  const start = startLineOf(doc, node);
108	  return { start: { line: start, ch: 0 }, end: subtreeContentEnd(node, start) };
109	}
110	
111	/**
112	 * The expand-only invariant (D4 amendment): the escalated range is the
113	 * UNION of the computed cover and the original range — escalation only
114	 * ever moves ends outward, never pulls one back. Without this, an end the
115	 * user placed beyond the cover (a trailing gap line, the document's final
116	 * empty line) would be dragged back to the last content character —
117	 * concretely, Select All in a no-frontmatter note would silently drop its
118	 * trailing newline from the selection (sharpest in a single-node note,
119	 * where the head-on-final-gap-line shape is exactly the gap-line trigger).
120	 * Returns the ORIGINAL range object when the union changes nothing, so
121	 * callers can use identity/equality to detect a real escalation.
122	 */
123	function expandToCover(range: LineRange, cover: Cover): LineRange {
124	  const lo = isBackward(range) ? range.head : range.anchor;
125	  const hi = isBackward(range) ? range.anchor : range.head;
126	  const newLo = posBefore(cover.start, lo) ? cover.start : lo;
127	  const newHi = posBefore(hi, cover.end) ? cover.end : hi;
128	  if (posEqual(newLo, lo) && posEqual(newHi, hi)) return range;
129	  return isBackward(range) ? { anchor: newHi, head: newLo } : { anchor: newLo, head: newHi };
130	}
131	
132	/**
133	 * Escalate one selection range per D4 (as amended). Returns `range`
134	 * unchanged for: empty ranges (cursors — never altered), ranges with
135	 * either end in the preamble (D5 jurisdiction), and ranges whose ends both
136	 * rest on a single node's own content lines. Escalates to the node's whole
137	 * subtree when a same-node range has an end on a trailing gap line (the
138	 * single-node-selection trigger), and to the minimal contiguous run of
139	 * whole sibling subtrees when the ends resolve to different nodes — in
140	 * both cases unioned with the original range (expand-only) and with
141	 * orientation preserved.
142	 */
143	export function escalateRange(doc: OutlineDoc, range: LineRange): LineRange {
144	  if (isEmpty(range)) return range;
145	
146	  const anchorNode = nodeAtLine(doc, range.anchor.line);
147	  const headNode = nodeAtLine(doc, range.head.line);
148	  if (!anchorNode || !headNode) return range; // preamble jurisdiction (D5)
149	
150	  if (anchorNode === headNode) {
151	    // Same node: untouched while both ends stay on the node's own content
152	    // lines; an end on a trailing gap line escalates to this one node's
153	    // subtree (the drag-past-the-end-selects-the-node gesture).
154	    const start = startLineOf(doc, anchorNode);
155	    const firstGapLine = start + anchorNode.lines.length;
156	    if (range.anchor.line < firstGapLine && range.head.line < firstGapLine) return range;
157	    return expandToCover(range, subtreeCoverOf(doc, anchorNode));
158	  }
159	
160	  const anchorPath = findPath(doc, anchorNode.id)!;
161	  const headPath = findPath(doc, headNode.id)!;
162	
163	  // Deepest common ancestor scope: the longest shared index prefix of the
164	  // two paths. When one node is an ancestor of the other (paths differ in
165	  // length with no divergence — the "selection leaves a parent" case, D4),
166	  // the scope is one level ABOVE the shallower node, so its own sibling
167	  // index is used as both endpoints' subtree index.
168	  let k = 0;
169	  while (k < anchorPath.length && k < headPath.length && anchorPath[k] === headPath[k]) k++;
170	  const scopeLen = k < anchorPath.length && k < headPath.length ? k : k - 1;
171	
172	  const scopePath = anchorPath.slice(0, scopeLen);
173	  const scopeChildren = childrenAtScope(doc, scopePath);
174	  const anchorIndex = anchorPath[scopeLen]!;
175	  const headIndex = headPath[scopeLen]!;
176	  const loIndex = Math.min(anchorIndex, headIndex);
177	  const hiIndex = Math.max(anchorIndex, headIndex);
178	  const firstSubtree = scopeChildren[loIndex]!;
179	  const lastSubtree = scopeChildren[hiIndex]!;
180	
181	  return expandToCover(range, {
182	    start: { line: startLineOf(doc, firstSubtree), ch: 0 },
183	    end: subtreeContentEnd(lastSubtree, startLineOf(doc, lastSubtree)),
184	  });
185	}
186	
187	/**
188	 * Escalate a full selection's ranges with the uniform multi-range rule (D4
189	 * amendment): every range is first escalated independently; if ANY range
190	 * escalated, every other non-empty in-jurisdiction range is then escalated
191	 * to at least its own node's whole subtree. The result is that an
192	 * escalated multi-range selection is always a set of whole-subtree ranges
193	 * — a multi-range copy concatenates complete subtrees, never a mix of
194	 * block-level and mid-node fragments. Cursors and preamble ranges are
195	 * never touched; when nothing escalates, all ranges come back unchanged.
196	 */
197	export function escalateRanges(doc: OutlineDoc, ranges: readonly LineRange[]): LineRange[] {
198	  const escalated = ranges.map((range) => escalateRange(doc, range));
199	  const anyEscalated = escalated.some((range, i) => !rangesEqual(range, ranges[i]!));
200	  if (!anyEscalated) return escalated;
201	
202	  return escalated.map((range, i) => {
203	    if (!rangesEqual(range, ranges[i]!)) return range; // already escalated
204	    if (isEmpty(range)) return range; // cursors never move
205	    const anchorNode = nodeAtLine(doc, range.anchor.line);
206	    const headNode = nodeAtLine(doc, range.head.line);
207	    if (!anchorNode || !headNode) return range; // preamble jurisdiction
208	    // An unchanged non-empty in-jurisdiction range is a same-node content
209	    // range — force it up to its node's whole subtree. (expandToCover also
210	    // makes the already-exact-cover case a clean no-op.)
211	    return expandToCover(range, subtreeCoverOf(doc, anchorNode));
212	  });
213	}
