1	/**
2	 * CM6 adapter for the enforcement funnel (design.md D1/D2/D4): a single
3	 * `EditorState.transactionFilter` that classifies every transaction in an
4	 * outline-mode editor and, for `selection-only` transactions, escalates
5	 * boundary-crossing selections. Gated per-transaction on outline mode via
6	 * the public `editorInfoField` — the same pattern keymap.ts's
7	 * grammarExtension and decorations.ts's decorationsExtension use.
8	 *
9	 * All decision logic is pure (classify.ts, escalate.ts); this module only
10	 * extracts facts from a `Transaction`, converts between CM6 character
11	 * offsets and line/ch positions, and applies the verdict. Document text is
12	 * NEVER touched here — the filter's only permitted mutation is selection
13	 * replacement (node-selection-enforcement), applied via the `[tr, {
14	 * selection }]` return idiom so it lands inside the SAME transaction: no
15	 * second dispatch, no history entry, no observable intermediate state.
16	 */
17	
18	import {
19	  EditorSelection,
20	  EditorState,
21	  Transaction,
22	  type Extension,
23	  type SelectionRange,
24	  type Text,
25	} from '@codemirror/state';
26	import { editorInfoField } from 'obsidian';
27	import type { OutlineDoc } from '../model';
28	import { classify, type ChangedLineSpan, type TransactionFacts } from '../classify';
29	import { escalateRanges, rangesEqual, type LinePos, type LineRange } from '../escalate';
30	import type { ModeSource } from './keymap';
31	import { parsedDoc } from './parsed-doc';
32	import type { TransactionStats } from './stats';
33	
34	export interface ClassificationSource extends ModeSource {
35	  readonly debugCrossCheck: boolean;
36	}
37	
38	function offsetToLinePos(doc: Text, pos: number): LinePos {
39	  const line = doc.lineAt(pos);
40	  return { line: line.number - 1, ch: pos - line.from };
41	}
42	
43	function linePosToOffset(doc: Text, pos: LinePos): number {
44	  return doc.line(pos.line + 1).from + pos.ch;
45	}
46	
47	/** Old-document (`tr.startState.doc`) line spans touched by this
48	 * transaction's changes — inclusive on both ends (classify.ts's
49	 * convention). A pure insertion (fromA === toA) only ever touches the one
50	 * line it lands on. */
51	function collectChangedLineSpans(tr: Transaction): ChangedLineSpan[] {
52	  const spans: ChangedLineSpan[] = [];
53	  tr.changes.iterChangedRanges((fromA, toA) => {
54	    const fromLine = tr.startState.doc.lineAt(fromA).number - 1;
55	    const toLine = tr.startState.doc.lineAt(Math.max(fromA, toA - 1)).number - 1;
56	    spans.push({ fromLine, toLine });
57	  });
58	  return spans;
59	}
60	
61	function toLineRange(doc: Text, range: SelectionRange): LineRange {
62	  return { anchor: offsetToLinePos(doc, range.anchor), head: offsetToLinePos(doc, range.head) };
63	}
64	
65	/**
66	 * Escalates the transaction's resulting selection (`tr.newSelection` — the
67	 * old selection unchanged for a selection-only transaction with no explicit
68	 * new selection, or the dispatched new selection otherwise) through the
69	 * pure `escalateRanges`, which applies both the per-range rules and the
70	 * uniform multi-range rule (D4 as amended). Returns `undefined` if no
71	 * range actually changed, so the caller can skip wrapping the transaction.
72	 */
73	function escalateSelection(
74	  outlineDoc: OutlineDoc,
75	  doc: Text,
76	  tr: Transaction,
77	): EditorSelection | undefined {
78	  const before = tr.newSelection.ranges.map((range) => toLineRange(doc, range));
79	  const after = escalateRanges(outlineDoc, before);
80	  let changed = false;
81	  const ranges = tr.newSelection.ranges.map((original, i) => {
82	    if (rangesEqual(before[i]!, after[i]!)) return original;
83	    changed = true;
84	    const anchor = linePosToOffset(doc, after[i]!.anchor);
85	    const head = linePosToOffset(doc, after[i]!.head);
86	    return EditorSelection.range(anchor, head);
87	  });
88	  if (!changed) return undefined;
89	  return EditorSelection.create(ranges, tr.newSelection.mainIndex);
90	}
91	
92	export function transactionFilterExtension(
93	  source: ClassificationSource,
94	  stats: TransactionStats,
95	): Extension {
96	  return EditorState.transactionFilter.of((tr) => {
97	    const path = tr.startState.field(editorInfoField, false)?.file?.path;
98	    if (!path || !source.isOutline(path)) return tr; // off-mode: byte-for-byte stock, nothing recorded
99	
100	    const start = performance.now();
101	    const userEvent = tr.annotation(Transaction.userEvent);
102	    const isComposition = tr.isUserEvent('input.type.compose');
103	    const changedLineSpans = collectChangedLineSpans(tr);
104	    const { doc: outlineDoc } = parsedDoc(tr.startState.doc);
105	
106	    const facts: TransactionFacts = { userEvent, isComposition, changedLineSpans };
107	    const cls = classify(facts, outlineDoc);
108	
109	    let result: Transaction | readonly [Transaction, { selection: EditorSelection }] = tr;
110	    if (cls === 'selection-only') {
111	      const escalated = escalateSelection(outlineDoc, tr.startState.doc, tr);
112	      if (escalated) result = [tr, { selection: escalated }];
113	    }
114	
115	    const ms = performance.now() - start;
116	    stats.record(cls, ms, userEvent);
117	    if (source.debugCrossCheck) {
118	      // console.warn (not .log), matching main.ts's existing crossCheck
119	      // logging under this same debug setting — one debug-console
120	      // convention across the plugin, not a new one.
121	      console.warn(
122	        `[true-outliner] tx classified "${cls}"`,
123	        { userEvent, isComposition, changedLineSpans, ms: Number(ms.toFixed(3)) },
124	      );
125	    }
126	
127	    return result;
128	  });
129	}
