1	/**
2	 * Classification observability surface (design.md D8): per-class counters,
3	 * per-class timing aggregates, and a bounded ring buffer of recent
4	 * classifications — exposed as a public field on the plugin instance so
5	 * the e2e harness (which already executes JS in the app and reads plugin
6	 * state, e.g. `isOutlineMode`) can assert on it directly. This turns each
7	 * Phase A choke-point assumption into a permanent, assertable regression
8	 * test instead of a one-off manual observation.
9	 */
10	
11	import type { TransactionClass } from '../classify';
12	
13	export interface ClassificationRecord {
14	  readonly cls: TransactionClass;
15	  readonly userEvent: string | undefined;
16	  readonly ms: number;
17	  readonly timestamp: number;
18	}
19	
20	export interface TimingSummary {
21	  readonly count: number;
22	  readonly median: number;
23	  readonly p95: number;
24	  readonly max: number;
25	}
26	
27	export interface StatsSnapshot {
28	  readonly counts: Record<TransactionClass, number>;
29	  readonly timing: Record<TransactionClass, TimingSummary>;
30	  readonly recent: readonly ClassificationRecord[];
31	}
32	
33	const ALL_CLASSES: readonly TransactionClass[] = [
34	  'programmatic',
35	  'composition',
36	  'plugin-own',
37	  'selection-only',
38	  'within-node-edit',
39	  'boundary-crossing-edit',
40	];
41	
42	/** Per-class sample cap — bounds memory on a long editing session; recent
43	 * samples are what the budget (D7) cares about, not full history. */
44	const MAX_SAMPLES_PER_CLASS = 1000;
45	const RING_BUFFER_SIZE = 200;
46	
47	function emptyTiming(): TimingSummary {
48	  return { count: 0, median: 0, p95: 0, max: 0 };
49	}
50	
51	function summarize(samples: readonly number[]): TimingSummary {
52	  if (samples.length === 0) return emptyTiming();
53	  const sorted = [...samples].sort((a, b) => a - b);
54	  const at = (p: number): number => sorted[Math.min(sorted.length - 1, Math.floor(p * sorted.length))]!;
55	  return { count: sorted.length, median: at(0.5), p95: at(0.95), max: sorted[sorted.length - 1]! };
56	}
57	
58	export class TransactionStats {
59	  private counts: Record<TransactionClass, number> = {
60	    programmatic: 0,
61	    composition: 0,
62	    'plugin-own': 0,
63	    'selection-only': 0,
64	    'within-node-edit': 0,
65	    'boundary-crossing-edit': 0,
66	  };
67	  private samples: Record<TransactionClass, number[]> = {
68	    programmatic: [],
69	    composition: [],
70	    'plugin-own': [],
71	    'selection-only': [],
72	    'within-node-edit': [],
73	    'boundary-crossing-edit': [],
74	  };
75	  private ring: ClassificationRecord[] = [];
76	
77	  record(cls: TransactionClass, ms: number, userEvent: string | undefined): void {
78	    this.counts[cls]++;
79	    const bucket = this.samples[cls];
80	    bucket.push(ms);
81	    if (bucket.length > MAX_SAMPLES_PER_CLASS) bucket.shift();
82	    this.ring.push({ cls, userEvent, ms, timestamp: Date.now() });
83	    if (this.ring.length > RING_BUFFER_SIZE) this.ring.shift();
84	  }
85	
86	  snapshot(): StatsSnapshot {
87	    const timing = {} as Record<TransactionClass, TimingSummary>;
88	    for (const cls of ALL_CLASSES) timing[cls] = summarize(this.samples[cls]);
89	    return { counts: { ...this.counts }, timing, recent: [...this.ring] };
90	  }
91	
92	  reset(): void {
93	    for (const cls of ALL_CLASSES) {
94	      this.counts[cls] = 0;
95	      this.samples[cls] = [];
96	    }
97	    this.ring = [];
98	  }
99	
100	  /** One-line-per-class human-readable summary for the dev command. */
101	  formatSummary(): string {
102	    const snap = this.snapshot();
103	    return ALL_CLASSES.map((cls) => {
104	      const t = snap.timing[cls];
105	      return `${cls}: ${snap.counts[cls]} (median ${t.median.toFixed(2)}ms, p95 ${t.p95.toFixed(2)}ms, max ${t.max.toFixed(2)}ms)`;
106	    }).join('\n');
107	  }
108	}
