1	/**
2	 * Line-surgery helpers: re-encode a node (and its subtree) for a new
3	 * destination. Only the lines that must change are rewritten; everything
4	 * else is carried verbatim.
5	 */
6	
7	import type { OutlineNode } from './model';
8	import { indentWidth } from './parse';
9	
10	const LIST_MARKER_RE = /^([ \t]*)([-+*]|\d{1,9}[.)])([ \t]?)/;
11	
12	export function markerWidth(node: OutlineNode): number {
13	  const match = LIST_MARKER_RE.exec(node.lines[0] ?? '');
14	  return match ? match[2]!.length + 1 : 2;
15	}
16	
17	/** The column at which a node's children must be indented. */
18	export function childBaseCol(parent: OutlineNode | 'root'): number {
19	  if (parent === 'root' || parent.kind === 'heading') return 0;
20	  const indent = indentWidth(parent.lines[0] ?? '');
21	  if (parent.kind === 'list-item') return indent + markerWidth(parent);
22	  return indent; // paragraph: child lists sit at the paragraph's own indent
23	}
24	
25	export function leadingWhitespace(line: string): string {
26	  return /^[ \t]*/.exec(line)?.[0] ?? '';
27	}
28	
29	function shiftLine(line: string, delta: number): string {
30	  if (line.trim() === '') return line;
31	  if (delta === 0) return line;
32	  const ws = leadingWhitespace(line);
33	  if (delta > 0) {
34	    // Insert AFTER existing leading whitespace: spaces before a tab would
35	    // vanish into the tab stop and corrupt the width arithmetic.
36	    return ws + ' '.repeat(delta) + line.slice(ws.length);
37	  }
38	  // Dedent: remove up to -delta columns of leading whitespace; when a tab
39	  // overshoots the target column, repair the difference with spaces.
40	  let remaining = -delta;
41	  let i = 0;
42	  while (i < ws.length && remaining > 0) {
43	    remaining -= ws[i] === '\t' ? 4 : 1;
44	    i++;
45	  }
46	  return (remaining < 0 ? ' '.repeat(-remaining) : '') + line.slice(i);
47	}
48	
49	export function shiftSubtree(node: OutlineNode, delta: number): OutlineNode {
50	  if (delta === 0) return node;
51	  return {
52	    ...node,
53	    lines: node.lines.map((line) => shiftLine(line, delta)),
54	    children: node.children.map((child) => shiftSubtree(child, delta)),
55	  };
56	}
57	
58	/**
59	 * Re-encode a moved node for its destination: the node ADOPTS the
60	 * destination's indentation string verbatim (`indentText` — tabs included,
61	 * taken from a sibling or parent at the landing site), and for
62	 * paragraph/list-item nodes converts to `newKind` when the context demands
63	 * it. Continuations and children shift by the resulting width delta.
64	 */
65	export function reencodeForDestination(
66	  node: OutlineNode,
67	  newKind: 'paragraph' | 'list-item' | undefined,
68	  indentText: string,
69	): OutlineNode {
70	  const first = node.lines[0] ?? '';
71	  const currentIndent = indentWidth(first);
72	  const targetIndent = indentWidth(indentText);
73	  const delta = targetIndent - currentIndent;
74	
75	  // Atoms and no-conversion cases: rewrite the first line's leading
76	  // whitespace exactly; shift the rest by the width delta.
77	  if (!newKind || newKind === node.kind) {
78	    const shifted = shiftSubtree(node, delta);
79	    return {
80	      ...shifted,
81	      lines: [
82	        indentText + (shifted.lines[0] ?? '').slice(leadingWhitespace(shifted.lines[0] ?? '').length),
83	        ...shifted.lines.slice(1),
84	      ],
85	    };
86	  }
87	
88	  if (node.kind === 'paragraph' && newKind === 'list-item') {
89	    const contPad = indentText + '  ';
90	    const lines = node.lines.map((line, i) =>
91	      i === 0 ? `${indentText}- ${line.trimStart()}` : `${contPad}${line.trimStart()}`,
92	    );
93	    const childDelta = targetIndent + 2 - childBaseCol(node);
94	    return {
95	      ...node,
96	      kind: 'list-item',
97	      listStyle: { type: 'bullet', marker: '-' },
98	      lines,
99	      children: node.children.map((child) => shiftSubtree(child, childDelta)),
100	    };
101	  }
102	
103	  if (node.kind === 'list-item' && newKind === 'paragraph') {
104	    const lines = node.lines.map((line, i) =>
105	      i === 0 ? `${indentText}${line.replace(LIST_MARKER_RE, '')}` : `${indentText}${line.trimStart()}`,
106	    );
107	    const childDelta = targetIndent - childBaseCol(node);
108	    const result: OutlineNode = {
109	      ...node,
110	      kind: 'paragraph',
111	      lines,
112	      children: node.children.map((child) => shiftSubtree(child, childDelta)),
113	    };
114	    delete (result as { listStyle?: unknown }).listStyle;
115	    return result;
116	  }
117	
118	  return shiftSubtree(node, delta);
119	}
120	
121	const ATX_RE = /^( {0,3})(#{1,6})([ \t]*)(.*)$/;
122	
123	/** All heading nodes in a subtree (including the root node if a heading). */
124	export function subtreeHeadings(node: OutlineNode): OutlineNode[] {
125	  const out: OutlineNode[] = [];
126	  const walk = (n: OutlineNode): void => {
127	    if (n.kind === 'heading') out.push(n);
128	    n.children.forEach(walk);
129	  };
130	  walk(node);
131	  return out;
132	}
133	
134	/**
135	 * A heading's lines at a new level. Setext headings are rewritten to ATX
136	 * whenever the level changes (an op-touched line; still lossless).
137	 */
138	export function headingWithLevel(node: OutlineNode, level: number): OutlineNode {
139	  const marker = '#'.repeat(level);
140	  let lines: string[];
141	  if (node.setext) {
142	    const text = (node.lines[0] ?? '').trim();
143	    lines = [`${marker} ${text}`];
144	  } else {
145	    const match = ATX_RE.exec(node.lines[0] ?? '');
146	    const text = match ? match[4]! : (node.lines[0] ?? '').trim();
147	    lines = [text === '' ? marker : `${marker} ${text}`];
148	  }
149	  const result: OutlineNode = { ...node, level, lines };
150	  delete (result as { setext?: unknown }).setext;
151	  return result;
152	}
