1	/**
2	 * Minimal line edits → editor change ranges ({line, ch} positions), for a
3	 * single `Editor.transaction`. Pure module, property-tested against the
4	 * library's own applyEdits.
5	 */
6	
7	import type { Edit } from '../result';
8	
9	export interface EditorPos {
10	  line: number;
11	  ch: number;
12	}
13	
14	export interface EditorChange {
15	  from: EditorPos;
16	  to: EditorPos;
17	  text: string;
18	}
19	
20	/**
21	 * Convert one line-range edit into a position-based change against the
22	 * buffer snapshot `lines` (the same snapshot the op was computed from).
23	 */
24	export function editToChange(lines: readonly string[], edit: Edit): EditorChange {
25	  const { fromLine, toLine, insert } = edit;
26	  const endOfDoc: EditorPos = {
27	    line: Math.max(0, lines.length - 1),
28	    ch: lines[lines.length - 1]?.length ?? 0,
29	  };
30	
31	  if (toLine < lines.length) {
32	    // Replacement ends before EOF: cover whole lines including their
33	    // terminating newlines.
34	    return {
35	      from: { line: fromLine, ch: 0 },
36	      to: { line: toLine, ch: 0 },
37	      text: insert.length > 0 ? insert.join('\n') + '\n' : '',
38	    };
39	  }
40	
41	  // Replacement reaches EOF: there is no newline after the last line.
42	  if (insert.length === 0) {
43	    // Pure deletion through EOF must also consume the newline before it.
44	    const from: EditorPos =
45	      fromLine === 0
46	        ? { line: 0, ch: 0 }
47	        : { line: fromLine - 1, ch: lines[fromLine - 1]?.length ?? 0 };
48	    return { from, to: endOfDoc, text: '' };
49	  }
50	  return { from: { line: fromLine, ch: 0 }, to: endOfDoc, text: insert.join('\n') };
51	}
52	
53	export function editsToChanges(lines: readonly string[], edits: readonly Edit[]): EditorChange[] {
54	  return edits.map((edit) => editToChange(lines, edit));
55	}
