1	/**
2	 * Block tree → markdown: pure span concatenation (design.md D2).
3	 * Emission order per node: own lines, trailing gap, then children —
4	 * which reproduces document order because blank-line runs are owned by
5	 * the node that precedes them.
6	 */
7	
8	import type { OutlineDoc, OutlineNode } from './model';
9	
10	export function encodeLines(doc: OutlineDoc): string[] {
11	  const out: string[] = [...doc.preamble];
12	  const emit = (node: OutlineNode): void => {
13	    out.push(...node.lines);
14	    out.push(...node.trailingGap);
15	    for (const child of node.children) emit(child);
16	  };
17	  for (const node of doc.children) emit(node);
18	  return out;
19	}
20	
21	export function encode(doc: OutlineDoc): string {
22	  return encodeLines(doc).join('\n');
23	}
