8	/** Find the node whose first line matches. */
9	function byLine(doc: OutlineDoc, line: string): number {
10	  for (const node of walkNodes(doc)) {
11	    if (node.lines[0] === line) return node.id;
12	  }
13	  throw new Error(`no node with line: ${line}`);
14	}
15	
16	function applyOk(
17	  op: typeof indent,
18	  md: string,
19	  line: string,
20	): { text: string; doc: OutlineDoc } {
21	  const doc = parse(md);
22	  const result = op(doc, byLine(doc, line));
23	  if (!result.ok) throw new Error(`unexpected rejection: ${result.rejection.reason}`);
24	  // The edit list must reproduce the encoding exactly.
25	  const viaEdits = applyEdits(md === '' ? [] : md.split('\n'), result.value.edits).join('\n');
26	  const text = encode(result.value.doc);
27	  expect(viaEdits).toBe(text);
28	  return { text, doc: result.value.doc };
29	}
