1	/**
2	 * Cursor-line → node resolution over a parsed document. A node owns its own
3	 * lines and its trailing gap; a cursor on a gap line resolves to the node
4	 * that precedes it. Preamble lines resolve to nothing.
5	 *
6	 * Lives in core (not src/plugin/) so pure core consumers — classify.ts's
7	 * change-range boundary checks, escalate.ts's selection-end resolution —
8	 * can use it without depending on the plugin layer. src/plugin/locate.ts
9	 * re-exports this for its existing CM6-adapter consumers.
10	 */
11	
12	import type { OutlineDoc, OutlineNode } from './model';
13	
14	export function nodeAtLine(doc: OutlineDoc, line: number): OutlineNode | undefined {
15	  let current = doc.preamble.length;
16	  if (line < current) return undefined;
17	  let found: OutlineNode | undefined;
18	  const walk = (node: OutlineNode): void => {
19	    if (found) return;
20	    const end = current + node.lines.length + node.trailingGap.length;
21	    if (line < end) {
22	      found = node;
23	      // Descend no further: children come after this node's own span.
24	      return;
25	    }
26	    current = end;
27	    node.children.forEach(walk);
28	  };
29	  doc.children.forEach(walk);
30	  return found;
31	}
