169	  /** All lines that resolve to a node, i.e. every candidate cursor line. */
170	  function resolvableLines(doc: ReturnType<typeof parse>, totalLines: number): number[] {
171	    const out: number[] = [];
172	    for (let i = 0; i < totalLines; i++) if (nodeAtLine(doc, i)) out.push(i);
