177	    fc.assert(
178	      fc.property(arbTree(), fc.nat(), fc.nat(), (tree, aPick, bPick) => {
179	        const text = encode(tree);
180	        const lines = text === '' ? [] : text.split('\n');
181	        const doc = parse(text);
182	        const candidates = resolvableLines(doc, lines.length);
183	        if (candidates.length < 2) return true;
184	        const aLine = candidates[aPick % candidates.length]!;
185	        const bLine = candidates[bPick % candidates.length]!;
186	        const r = range(pos(aLine, 0), pos(bLine, (lines[bLine] ?? '').length));
187	        const once = escalateRange(doc, r);
188	        const twice = escalateRange(doc, once);
189	        return once.anchor.line === twice.anchor.line &&
190	          once.anchor.ch === twice.anchor.ch &&
191	          once.head.line === twice.head.line &&
