199	    fc.assert(
200	      fc.property(arbTree(), fc.nat(), fc.nat(), (tree, aPick, bPick) => {
201	        const text = encode(tree);
202	        const lines = text === '' ? [] : text.split('\n');
203	        const doc = parse(text);
204	        const candidates = resolvableLines(doc, lines.length);
205	        if (candidates.length < 2) return true;
206	        const aLine = candidates[aPick % candidates.length]!;
207	        const bLine = candidates[bPick % candidates.length]!;
208	        if (aLine === bLine) return true; // same line = same node, no escalation
209	        const r = range(pos(aLine, 0), pos(bLine, 0));
210	        const result = escalateRange(doc, r);
211	        const wasBackward = bLine < aLine;
212	        const isBackwardNow = result.head.line < result.anchor.line ||
