256	  private async warnAboutConflicts(): Promise<void> {
257	    if (this.data.coexistenceWarned) return;
258	    const configPath = `${this.app.vault.configDir}/community-plugins.json`;
259	    let enabled: string[] = [];
260	    try {
261	      enabled = JSON.parse(await this.app.vault.adapter.read(configPath)) as string[];
262	    } catch {
263	      return; // no community plugins file — nothing to warn about
264	    }
265	    const conflicts = CONFLICTING_PLUGINS.filter((id) => enabled.includes(id));
266	    if (conflicts.length === 0) return;
267	    new Notice(
268	      `True Outliner: ${conflicts.join(' and ')} ${conflicts.length > 1 ? 'are' : 'is'} enabled — ` +
269	        'overlapping outliner behavior and keybindings may conflict.',
270	      8000,
271	    );
272	    this.data.coexistenceWarned = true;
273	    await this.saveData(this.data);
274	  }
