146	
147	interface Coords {
148	  left: number;
149	  top: number;
150	  bottom: number;
151	}
152	
153	function readCoordsAt(line: number, ch: number): Promise<Coords | null> {
154	  return browser.executeObsidian(
155	    ({ app, obsidian }, line, ch) => {
156	      const view = app.workspace.getActiveViewOfType(obsidian.MarkdownView);
157	      if (!view) throw new Error('no active markdown view');
158	      const cm = (view.editor as any).cm;
159	      const pos = cm.state.doc.line(line + 1).from + ch;
160	      const coords = cm.coordsAtPos(pos);
161	      return coords ? { left: coords.left, top: coords.top, bottom: coords.bottom } : null;
162	    },
163	    line,
164	    ch,
165	  );
166	}
167	
168	/** Scrolls a document position into view without touching selection/cursor
169	 * — dispatches CM6's own `EditorView.scrollIntoView` StateEffect, reached
170	 * via the live instance's own constructor (the only reference to the
171	 * `EditorView` class available in this browser-context script). */
172	function scrollPositionIntoView(line: number, ch: number): Promise<void> {
173	  return browser.executeObsidian(
174	    ({ app, obsidian }, line, ch) => {
175	      const view = app.workspace.getActiveViewOfType(obsidian.MarkdownView);
176	      if (!view) throw new Error('no active markdown view');
177	      const cm = (view.editor as any).cm;
178	      const pos = cm.state.doc.line(line + 1).from + ch;
179	      cm.dispatch({ effects: (cm.constructor as any).scrollIntoView(pos, { y: 'center' }) });
180	    },
181	    line,
182	    ch,
183	  );
184	}
185	
186	/**
187	 * Viewport pixel coordinates of a document position, via CM6's own
188	 * `coordsAtPos` — precise per-character placement, unlike approximating
189	 * from a `.cm-line`'s bounding rect. On a large (virtualized) document the
190	 * target position may not currently be rendered (`coordsAtPos` returns
191	 * null for anything outside CM6's render window), so this scrolls it into
192	 * view and polls — a scroll dispatch doesn't synchronously reflow within
193	 * one `executeObsidian` call, so `waitUntil` gives the browser real turns
194	 * to actually repaint between checks.
195	 */
196	export async function posToCoords(line: number, ch: number): Promise<Coords> {
197	  let coords = await readCoordsAt(line, ch);
198	  if (!coords) {
199	    await scrollPositionIntoView(line, ch);
200	    await browser.waitUntil(
201	      async () => {
202	        coords = await readCoordsAt(line, ch);
203	        return coords !== null;
204	      },
205	      { timeout: 3000, timeoutMsg: `no coords at line ${line} ch ${ch} after scrolling into view` },
206	    );
207	  }
208	  return coords!;
209	}
