211	/**
212	 * Real mouse drag selection: a genuine W3C pointer down/move.../up sequence
213	 * (not `Editor.setSelection`), so it exercises the SAME `select.pointer`
214	 * userEvent path a real user's drag produces — the thing Phase A's
215	 * choke-point claim ("every mutation path flows through the filter") is
216	 * actually about. `steps` intermediate moves let a test assert the
217	 * live-drag stability scenario (each pointer update stays escalated, no
218	 * flicker), not just the final released position.
219	 */
220	export async function mouseDragSelect(
221	  from: { line: number; ch: number },
222	  to: { line: number; ch: number },
223	  steps = 3,
224	): Promise<void> {
225	  const fromCoords = await posToCoords(from.line, from.ch);
226	  const toCoords = await posToCoords(to.line, to.ch);
227	  const fromY = Math.round((fromCoords.top + fromCoords.bottom) / 2);
228	  const toY = Math.round((toCoords.top + toCoords.bottom) / 2);
229	  const fromX = Math.round(fromCoords.left);
230	  const toX = Math.round(toCoords.left);
231	
232	  const action = browser.action('pointer', { parameters: { pointerType: 'mouse' } });
233	  action.move({ x: fromX, y: fromY, origin: 'viewport' }).down({ button: 0 }).pause(20);
234	  for (let i = 1; i <= steps; i++) {
235	    const t = i / steps;
236	    action.move({
237	      x: Math.round(fromX + (toX - fromX) * t),
238	      y: Math.round(fromY + (toY - fromY) * t),
239	      origin: 'viewport',
240	      duration: 30,
241	    });
242	  }
243	  action.up({ button: 0 });
244	  await action.perform();
245	}
246	
247	/** A real double-click at a document position (word selection). */
248	export async function doubleClickAt(line: number, ch: number): Promise<void> {
249	  const coords = await posToCoords(line, ch);
250	  const x = Math.round(coords.left);
251	  const y = Math.round((coords.top + coords.bottom) / 2);
252	  await browser
253	    .action('pointer', { parameters: { pointerType: 'mouse' } })
254	    .move({ x, y, origin: 'viewport' })
255	    .down({ button: 0 })
256	    .up({ button: 0 })
257	    .pause(10)
258	    .down({ button: 0 })
259	    .up({ button: 0 })
260	    .perform();
261	}
262	
263	/**
264	 * Dispatches a real multi-range selection transaction directly through the
265	 * live CM6 instance, annotated with a genuine `select`-family userEvent —
266	 * for the multi-range escalation scenario, where simulating the actual
267	 * "add a selection range" mouse/keyboard gesture (Cmd/Ctrl+click then
268	 * Shift+click, CM6's standard two-step pattern) turned out to be
269	 * unreliable in this harness: a modifier held via `perform(true)` across
270	 * separate `performActions` calls did not survive to the next call
271	 * (verified empirically — both a held-modifier drag and a held-modifier
272	 * click behaved as if no modifier were held at all, replacing the
273	 * selection instead of adding to it). This is a harness/WebDriver-session
274	 * limitation, not a plugin behavior under test, so it's worked around by
275	 * exercising the SAME real adapter code path (the actual registered
276	 * `transactionFilter`, unmocked) through a direct dispatch instead of a
277	 * simulated gesture — every single-range scenario elsewhere in this suite
278	 * already covers genuine mouse/keyboard input; this covers the one thing
279	 * that's specifically about multi-range iteration.
280	 */
281	export async function dispatchSelectOnlyRanges(
282	  ranges: readonly { anchor: { line: number; ch: number }; head: { line: number; ch: number } }[],
283	): Promise<void> {
284	  await browser.executeObsidian(
285	    ({ app, obsidian }, ranges) => {
286	      const view = app.workspace.getActiveViewOfType(obsidian.MarkdownView);
287	      if (!view) throw new Error('no active markdown view');
288	      const cm = (view.editor as any).cm;
289	      const Selection = cm.state.selection.constructor;
290	      const toOffset = (pos: { line: number; ch: number }) =>
291	        cm.state.doc.line(pos.line + 1).from + pos.ch;
292	      const cmRanges = ranges.map((r: (typeof ranges)[number]) =>
293	        Selection.range(toOffset(r.anchor), toOffset(r.head)),
294	      );
295	      cm.dispatch({ selection: Selection.create(cmRanges), userEvent: 'select' });
296	    },
297	    ranges,
298	  );
299	}
