641	/**
642	 * Poll the active editor's content DOM for a selector's match count, rather
643	 * than sleeping a fixed duration — a widget-replaced atom (table/callout/
644	 * html/hr) can settle its own DOM asynchronously after our decoration patch
645	 * runs, so a fixed pause is a race against however long that happens to take
646	 * (worse under system load). Waits until `expected` is observed, or throws.
647	 */
648	export async function waitForContentChildCount(
649	  selector: string,
650	  expected: number,
651	  timeout = 5000,
652	): Promise<void> {
653	  await browser.waitUntil(
654	    async () => {
655	      const count = await browser.executeObsidian(
656	        ({ app, obsidian }, selector) => {
657	          const view = app.workspace.getActiveViewOfType(obsidian.MarkdownView);
658	          if (!view) return -1;
659	          const cm = (view.editor as any).cm;
660	          return cm.contentDOM.querySelectorAll(selector).length as number;
661	        },
662	        selector,
663	      );
664	      return count === expected;
665	    },
666	    { timeout, timeoutMsg: `expected ${expected} "${selector}" element(s) within ${timeout}ms` },
667	  );
668	}
