1	/**
2	 * Parse cache for the transaction filter (design.md D7): a module-level
3	 * `WeakMap<Text, OutlineDoc>` keyed by CM6's immutable `Text` instance, so
4	 * every transaction against the same document version — and, crucially,
5	 * every `selection-only` transaction, whose doc is unchanged — shares one
6	 * parse. No `StateField`, so no extension-ordering coupling with the rest
7	 * of the filter. A separate cache from decorations.ts's own `docFacts`
8	 * (different shape: this stores the bare tree, not decoration facts) but
9	 * the same pattern, and reusable by any other consumer later (D7).
10	 */
11	
12	import type { Text } from '@codemirror/state';
13	import type { OutlineDoc } from '../model';
14	import { parse } from '../parse';
15	
16	export interface ParsedDocResult {
17	  readonly doc: OutlineDoc;
18	  /** Wall-clock ms spent parsing — 0 on a cache hit. Folded into the
19	   * filter's own per-transaction timing (D7's classification budget
20	   * explicitly includes tree access), exposed separately here for
21	   * diagnosing whether cache misses or classification itself dominates. */
22	  readonly parseMs: number;
23	}
24	
25	const cache = new WeakMap<Text, OutlineDoc>();
26	
27	export function parsedDoc(text: Text): ParsedDocResult {
28	  const cached = cache.get(text);
29	  if (cached) return { doc: cached, parseMs: 0 };
30	  const start = performance.now();
31	  const doc = parse(text.toString());
32	  const parseMs = performance.now() - start;
33	  cache.set(text, doc);
34	  return { doc, parseMs };
35	}
