    return edit.insert === '' ? PASS : computePasteVerdict(doc, edit);
  }
  // A deletion whose OLD-document range ends exactly at the next line's
  // start is always EITHER a genuine single-separator merge candidate OR a
  // gap-interior deletion (shrinking a multi-blank-line run by one line,
  // which never touches real content and is safe to leave native) — never
  // a case for the subtree-cover deletion path below. isSingleSeparatorMerge
  // itself distinguishes the two by checking the departing node's own
  // trailing-gap length.
  if (edit.insert === '' && edit.to.line === edit.from.line + 1 && edit.to.ch === 0) {
    return isSingleSeparatorMerge(doc, edit) ? computeMergeVerdict(doc, edit) : PASS;
  }
  return computeDeletionVerdict(doc, edit);
}

