function deepestLastDescendant(node: OutlineNode): OutlineNode {
  const last = node.children[node.children.length - 1];
  return last ? deepestLastDescendant(last) : node;
}

/** End position of an inserted node's own subtree content — the cursor spot
 * that makes continued typing (or a follow-up single-key type-over
 * keystroke) land AFTER the just-inserted content instead of before it.
 * `insertSubtrees`/`finalize`'s own cursor convention (content-START of the
 * first affected node) is right for one-shot structural commands, but wrong
 * for text the user is actively typing over a selection. */
function endOfInsertedNode(doc: OutlineDoc, id: number): { line: number; ch: number } {
  const path = findPath(doc, id)!;
  const leaf = deepestLastDescendant(nodeAt(doc, path)!);
  const leafStart = startLineOf(doc, leaf.id);
  const lastLine = leaf.lines[leaf.lines.length - 1] ?? '';
  return { line: leafStart + leaf.lines.length - 1, ch: lastLine.length };
}

