function contentAfterMarker(node: OutlineNode): string {
  const line = node.lines[0] ?? '';
  if (node.kind !== 'list-item') return line;
  const match = LIST_MARKER_SPLIT_RE.exec(line);
  return match ? line.slice(match[0].length) : line;
}

/**
 * Per-kind merge table (structural-operations delta, pinned here): only
 * paragraph←paragraph and list-item←list-item of the SAME list-style family
 * (bullet with bullet, ordered with ordered — the marker character itself
 * need not match, the surviving node keeps its own) join as a minimal
 * content-level edit. Every other combination rejects: cross-kind joins
 * (paragraph↔list-item), atoms (opaque units, never mergeable), headings
 * (absorbing one destroys its section's positional anchor), and either side
 * having children (the join would orphan them — no valid re-parenting
 * target exists for a node that is about to disappear into its neighbor).
 */
export function mergeNodes(doc: OutlineDoc, firstId: number): OpResult<OpOutput> {
  const path = findPath(doc, firstId);
  if (!path) return reject('node-not-found');
  const first = nodeAt(doc, path)!;
  const nextPath = rawSuccessorPath(doc, path);
  if (!nextPath) return reject('no-following-neighbor');
  const second = nodeAt(doc, nextPath)!;

  if (first.children.length > 0 || second.children.length > 0) {
    return reject('would-orphan-children');
  }
  const MERGEABLE: ReadonlySet<NodeKind> = new Set<NodeKind>(['paragraph', 'list-item']);
  if (!MERGEABLE.has(first.kind) || !MERGEABLE.has(second.kind) || first.kind !== second.kind) {
    return reject('merge-not-expressible');
  }
  if (
    first.kind === 'list-item' &&
    first.listStyle!.type !== (second.listStyle as { type: 'bullet' | 'ordered' }).type
  ) {
    return reject('merge-not-expressible');
  }

  const mergedFirstLine = (first.lines[first.lines.length - 1] ?? '') + contentAfterMarker(second);
  const merged: OutlineNode = {
    ...first,
    lines: [...first.lines.slice(0, -1), mergedFirstLine, ...second.lines.slice(1)],
    trailingGap: second.trailingGap,
  };

  const firstParentPath = path.slice(0, -1);
  const firstIndex = path[path.length - 1]!;
  const secondParentPath = nextPath.slice(0, -1);
  const secondIndex = nextPath[nextPath.length - 1]!;

  let surgery: OutlineDoc;
  if (arraysEqual(firstParentPath, secondParentPath)) {
    surgery = updateSiblings(doc, firstParentPath, (nodes) =>
      renumberOrdered([
        ...nodes.slice(0, firstIndex),
        merged,
        ...nodes.slice(firstIndex + 1, secondIndex),
        ...nodes.slice(secondIndex + 1),
      ]),
    );
  } else {
    // `second` sits at a shallower scope, reached by walking up past `first`
    // (which has no children, per the check above): remove it from its own
    // level first, then replace `first` in place at its own level.
    surgery = updateSiblings(doc, secondParentPath, (nodes) =>
      renumberOrdered([...nodes.slice(0, secondIndex), ...nodes.slice(secondIndex + 1)]),
    );
    surgery = updateSiblings(surgery, firstParentPath, (nodes) =>
      nodes.map((n, i) => (i === firstIndex ? merged : n)),
    );
  }

  return finalize(doc, surgery, merged.id);
}

