/**
 * Single-separator merge shape (design.md D4): a pure deletion of exactly
 * the one character joining two adjacent lines — Backspace at a node's
 * first character or Delete at its last. Deleting INSIDE a gap (shrinking a
 * multi-blank-line run by one line) is deliberately excluded: that shape is
 * safe to leave native (it never touches content, the tree is structurally
 * unchanged), so only a deletion landing exactly on the boundary's owning
 * node's own LAST CONTENT line (empty trailing gap) counts as a real merge
 * candidate.
 */
/** The deletion's OLD-document range removes NOTHING but the single line
 * break ending `from.line` — i.e. `from` sits at that line's own end and
 * `to` at the very start of the next. Distinct from "ends at a line start"
 * in general: a whole-line-or-more deletion (e.g. removing an entire node)
 * can ALSO end at ch 0 of a later line without this being true. */
function isPureNewlineDeletion(doc: OutlineDoc, edit: EditFact): boolean {
  if (edit.insert !== '') return false;
  if (edit.to.line !== edit.from.line + 1 || edit.to.ch !== 0) return false;
  const lineLen = (encodeLines(doc)[edit.from.line] ?? '').length;
  return edit.from.ch === lineLen;
}

function isSingleSeparatorMerge(doc: OutlineDoc, edit: EditFact): boolean {
  if (!isPureNewlineDeletion(doc, edit)) return false;
  const node = nodeAtLine(doc, edit.from.line);
  if (!node) return false;
  const contentEndLine = startLineOf(doc, node.id) + node.lines.length - 1;
  return edit.from.line === contentEndLine && node.trailingGap.length === 0;
}

function computeMergeVerdict(doc: OutlineDoc, edit: EditFact): Verdict {
  const firstNode = nodeAtLine(doc, edit.from.line);
  if (!firstNode) return PASS; // unreachable given isSingleSeparatorMerge's own check
  const result = mergeNodes(doc, firstNode.id);
  if (!result.ok) return vetoFrom(result);
  return rewriteFrom(result.value, 'delete.structural.merge');
}

