  return 'native';
}

function computeMergeVerdict(
  doc: OutlineDoc,
  intent: number | 'veto-no-predecessor',
): Verdict {
  if (intent === 'veto-no-predecessor') {
    return { kind: 'veto', reason: 'no-following-neighbor' };
