it('a structure-corrupting merge vetoes with the rejection cue; buffer stays byte-identical', async function () {
  // No blank line before the heading (an ATX heading always segments on
  // its own) — the zero-gap adjacency Backspace-at-heading-start needs to
  // actually reach the merge shape in one keystroke.
  const md = 'Intro.\n## Section\n\nChild body.\n';
  await outlineNote(md);
  await h.setCursor(1, 0); // start of "## Section"
  await browser.keys(Key.Backspace);
  await h.waitForNotice(REJECTION_MESSAGES['would-orphan-children']);
  expect(await h.getBuffer()).toBe(md);
  const snap = await h.getStats();
  expect(snap.verdictCounts.veto).toBeGreaterThan(0);
});

it('finding: two plain paragraphs always carry a real gap, so Backspace still joins them correctly via native passes (never an enforced merge)', async function () {
  // A genuinely-parsed document can never have two sibling PARAGRAPH
  // nodes with zero gap (the parser always folds ungapped text lines into
  // one node already) — so paragraph←paragraph is reachable as a
  // mergeNodes REWRITE only from a non-organic starting state (verified
  // directly at the unit level, tests/edit-ops.test.ts). The organic
  // two-Backspace gesture below still produces the byte-correct result —
  // the first Backspace shrinks the gap (pass), and by the second the
  // buffer already reparses as one node, so it's an ordinary within-node
  // edit, not a rewrite. Recorded per the design's migration-plan finding
  // discipline (D2's merge table note).
  await outlineNote('First.\n\nSecond.\n');
  await h.setCursor(2, 0); // start of "Second."
  await browser.keys(Key.Backspace);
  expect(await h.getBuffer()).toBe('First.\nSecond.\n');
  await browser.keys(Key.Backspace);
  expect(await h.getBuffer()).toBe('First.Second.\n');
  const snap = await h.getStats();
  expect(snap.verdictCounts.rewrite).toBe(0);
});

