 * Structural-paste rule (design.md D5): a pure insertion whose text parses
 * as a multi-block sequence, landing inside a node, splices at the nearest
 * boundary AFTER that node. Conservative on failure: an inexpressible
 * sequence (or ambiguous shape) stays native rather than surprising the
 * user with a veto — "a wrong pass is editable text; a wrong rewrite is
 * surprising relocation."
 */
function computePasteVerdict(doc: OutlineDoc, edit: EditFact): Verdict {
  const node = nodeAtLine(doc, edit.from.line);
  if (!node) return PASS;
  const parsedBlocks = parse(edit.insert).children;
  if (parsedBlocks.length <= 1) return PASS;

