import { describe, it } from 'vitest';
import { parse } from '../src/parse';
import { encode } from '../src/encode';
import { computeVerdict, type EditFact } from '../src/enforce';
import { applyEdits } from '../src/result';

const pos = (line: number, ch: number) => ({ line, ch });

function applyVerdict(md: string, verdict: any): string {
  const lines = md === '' ? [] : md.split('\n');
  return applyEdits(lines, verdict.edits).join('\n');
}

describe('scratch depth sweep via computeVerdict', () => {
  it('sweep with realistic multi-sibling doc', () => {
    const results: Record<string, any> = {};
    // A more realistic doc: each level has 2 siblings, going 5 levels deep.
    const buildRealistic = (depth: number): string => {
      const lines: string[] = [];
      let indent = '';
      for (let i = 0; i <= depth; i++) {
        lines.push(`${indent}- item${i}a`);
        lines.push(`${indent}- item${i}b`);
        indent += '\t';
      }
      return lines.join('\n') + '\n';
    };
    for (let depth = 0; depth <= 5; depth++) {
      const md = buildRealistic(depth);
      const doc = parse(md);
      // Anchor: the LAST "b" item at the deepest level (end of its line).
      const lines = md.split('\n');
      const anchorLineIdx = lines.findIndex((l) => l === '\t'.repeat(depth) + `- item${depth}b`);
      const anchorLine = lines[anchorLineIdx]!;
      const edit: EditFact = {
        from: pos(anchorLineIdx, anchorLine.length),
        to: pos(anchorLineIdx, anchorLine.length),
        insert: '- x\n\t- y\n',
      };
      const verdict = computeVerdict('boundary-crossing-edit', doc, edit);
      results[`depth${depth}`] = verdict.kind === 'rewrite' ? applyVerdict(md, verdict) : verdict.kind;
    }
    throw new Error(JSON.stringify(results, null, 2));
  });
});
