    const results: Record<string, any> = {};
    for (let depth = 0; depth <= 6; depth++) {
      const lines: string[] = [];
      for (let i = 0; i <= depth; i++) lines.push('\t'.repeat(i) + `- level${i}`);
      // Add a real subtree to copy: "- x" with child "- y", at TOP level (0).
      lines.push('- x');
      lines.push('\t- y');
      const md = lines.join('\n') + '\n';
      await h.createNote(NOTE, md);
      if (!(await h.isOutlineMode(NOTE))) {
        await h.toggleOutlineMode();
        await h.waitForNotice('Outline mode on');
        await h.dismissNotices();
      }
      await h.resetStats();
      const xLineIdx = depth + 1;
      const yLineIdx = depth + 2;
      // Select "- x" and its child "- y" (drag from x's start to y's end).
      await h.mouseDragSelect({ line: xLineIdx, ch: 0 }, { line: yLineIdx, ch: '\t- y'.length }, 6);
      await browser.keys([PRIMARY_MOD, 'c']);
      await browser.pause(50);
      // Now place cursor at the anchor (deepest level item) and paste.
      const anchorLineText = '\t'.repeat(depth) + `- level${depth}`;
      await h.setCursor(depth, anchorLineText.length);
      await browser.keys([PRIMARY_MOD, 'v']);
      await browser.pause(100);
      const buf = await h.getBuffer();
      const stats = await h.getStats();
      results[`depth${depth}`] = { buf, verdict: stats.verdictCounts };
    }
    throw new Error(JSON.stringify(results, null, 2));
  });
});
